from openai import OpenAI
import json

client = OpenAI()

# Route selector: a small set of category tools
CATEGORY_TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "select_category",
            "description": "Select the tool category for this request.",
            "parameters": {
                "type": "object",
                "properties": {
                    "category": {
                        "type": "string",
                        "enum": ["finance", "weather", "calendar", "documents"],
                        "description": "The category of tool needed.",
                    }
                },
                "required": ["category"],
                "additionalProperties": False,
            }
        }
    }
]

# Per-category tool sets (defined elsewhere)
TOOLS_BY_CATEGORY = {
    "finance": [get_stock_tool, get_earnings_tool, get_portfolio_tool],
    "weather": [get_weather_tool, get_forecast_tool],
    "calendar": [create_event_tool, list_events_tool, delete_event_tool],
    "documents": [search_docs_tool, get_doc_tool, summarize_doc_tool],
}

def route_and_execute(user_message: str) -> str:
    # Step 1: categorise
    route_response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[{"role": "user", "content": user_message}],
        tools=CATEGORY_TOOLS,
        tool_choice="required",
    )
    category_call = route_response.choices[0].message.tool_calls[0]
    category = json.loads(category_call.function.arguments)["category"]

    # Step 2: call with only the relevant tools
    messages = [
        {"role": "user", "content": user_message},
    ]
    final = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=messages,
        tools=TOOLS_BY_CATEGORY[category],
        tool_choice="auto",
    )
    # ... dispatch tool call and return answer
    return final.choices[0].message.content

print(route_and_execute("Search for the Q3 earnings report on Apple."))
